.darma-loader-darma-custom-659 {

  --color: var(--loader-color, #94a3b8);
  --size: 70px;
  width: var(--size);
  height: var(--size);
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 5px;
}

.darma-loader-darma-custom-659 span {
  width: 100%;
  height: 100%;
  background-color: var(--color);
  animation: darma-loader-darma-custom-659-keyframes-blink 0.6s alternate infinite linear;
}

.darma-loader-darma-custom-659 span:nth-child(1) {
  animation-delay: 0ms;
}

.darma-loader-darma-custom-659 span:nth-child(2) {
  animation-delay: 200ms;
}

.darma-loader-darma-custom-659 span:nth-child(3) {
  animation-delay: 300ms;
}

.darma-loader-darma-custom-659 span:nth-child(4) {
  animation-delay: 400ms;
}

.darma-loader-darma-custom-659 span:nth-child(5) {
  animation-delay: 500ms;
}

.darma-loader-darma-custom-659 span:nth-child(6) {
  animation-delay: 600ms;
}

@keyframes darma-loader-darma-custom-659-keyframes-blink {
  0% {
    opacity: 0.3;
    transform: scale(0.5) rotate(5deg);
  }

  50% {
    opacity: 1;
    transform: scale(1);
  }
}

